import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.saml2.provider.service.authentication.Saml2Authentication;
import org.springframework.security.saml2.provider.service.registration.RelyingPartyRegistrationRepository;
import org.springframework.security.saml2.provider.service.web.authentication.Saml2AuthenticationRequestFilter;
import org.springframework.security.saml2.provider.service.web.authentication.Saml2AuthenticationRequestResolver;
import org.springframework.security.saml2.provider.service.web.authentication.Saml2WebSsoAuthenticationFilter;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.AuthenticationSuccessHandler;
import org.springframework.security.web.authentication.SimpleUrlAuthenticationSuccessHandler;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ResponseBody;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;
import org.xml.sax.InputSource;

import javax.servlet.http.HttpSession;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.StringReader;
import java.util.HashMap;
import java.util.Map;

@SpringBootApplication
public class SamlServiceProviderApplication {

    public static void main(String[] args) {
        SpringApplication.run(SamlServiceProviderApplication.class, args);
    }

    @Controller
    public class SamlController {

        @GetMapping("/saml/response")
        @ResponseBody
        public String processSamlResponse(Saml2Authentication authentication, HttpSession session) {
            try {
                String samlResponse = authentication.getSaml2Response();
                DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
                factory.setNamespaceAware(true);
                DocumentBuilder builder = factory.newDocumentBuilder();
                Document document = builder.parse(new InputSource(new StringReader(samlResponse)));

                Element assertion = (Element) document.getElementsByTagNameNS("*", "Assertion").item(0);
                NodeList attributes = assertion.getElementsByTagNameNS("*", "Attribute");

                Map<String, String> userAttributes = new HashMap<>();
                for (int i = 0; i < attributes.getLength(); i++) {
                    Element attribute = (Element) attributes.item(i);
                    String name = attribute.getAttribute("Name");
                    String value = attribute.getTextContent();
                    userAttributes.put(name, value);
                }

                session.setAttribute("userAttributes", userAttributes);
                return "SAML Response Processed Successfully";
            } catch (Exception e) {
                return "Error processing SAML Response: " + e.getMessage();
            }
        }
    }

    @org.springframework.context.annotation.Configuration
    public class SecurityConfiguration {

        private final RelyingPartyRegistrationRepository relyingPartyRegistrationRepository;

        public SecurityConfiguration(RelyingPartyRegistrationRepository relyingPartyRegistrationRepository) {
            this.relyingPartyRegistrationRepository = relyingPartyRegistrationRepository;
        }

        public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
            http
                .authorizeRequests(authorize -> authorize.anyRequest().authenticated())
                .saml2Login(saml2 -> saml2
                    .relyingPartyRegistrationRepository(this.relyingPartyRegistrationRepository)
                    .successHandler(successHandler()))
                .addFilterBefore(new Saml2AuthenticationRequestFilter(
                        new Saml2AuthenticationRequestResolver(this.relyingPartyRegistrationRepository)),
                        Saml2WebSsoAuthenticationFilter.class);

            return http.build();
        }

        private AuthenticationSuccessHandler successHandler() {
            return new SimpleUrlAuthenticationSuccessHandler("/saml/response");
        }
    }
}